import React, { useEffect, useState, useCallback, useMemo } from 'react';
import api from '../api/axiosConfig';
import { useTheme } from '../context/ThemeContext';
import ReactMarkdown from 'react-markdown';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Eye, X, BarChart3, AlignLeft } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const { isDark } = useTheme();
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selectedItem, setSelectedItem] = useState(null);

  const fetchHistory = useCallback(async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("VAULT_SYNC_FAILURE");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchHistory(); }, [fetchHistory]);

  // 1. DYNAMIC OVERLAY CALCULATION
  const overlayStyle = useMemo(() => ({
    position: 'fixed',
    inset: 0,
    background: isDark ? 'rgba(0, 0, 0, 0.98)' : 'rgba(255, 255, 255, 0.9)',
    backdropFilter: 'blur(20px)',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    zIndex: 9999
  }), [isDark]);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div style={containerStyle}>
      {/* Header */}
      <div style={headerRow}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
          <Archive size={24} color="var(--accent-primary)"/>
          <h2 style={headerStyle}>STRATEGY_VAULT</h2>
        </div>
        <span style={vaultBadge}>{history.length} NODES</span>
      </div>

      {/* Strategy List */}
      <div style={listStyle}>
        {history.map((item) => (
          <div key={item.id} className="vault-card" style={cardStyle}>
            <div style={{ flex: 1 }}>
              <div style={tagRow}>
                <span style={metaText}><Calendar size={14}/> {new Date(item.created_at).toLocaleDateString()}</span>
                <span style={riskTag}><ShieldCheck size={14}/> RISK: {item.risk_score}</span>
              </div>
              <h4 style={titleStyle}>{item.goal}</h4>
            </div>
            <div style={actionColumn}>
              <button onClick={() => setSelectedItem(item)} style={iconBtn} title="View"><Eye size={20}/></button>
              <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Delete"><Trash2 size={20}/></button>
            </div>
          </div>
        ))}
      </div>

      {/* ── OLED BLACK DESCRIPTION MODAL ── */}
      {selectedItem && (
        <div style={overlayStyle}>
          <div style={{
            ...modalContent,
            background: isDark ? '#000000' : '#ffffff', // FORCED BLACK
            border: `1px solid ${isDark ? '#333' : 'var(--surface-border)'}`
          }}>
            <div style={{
              ...modalHeader,
              background: isDark ? '#000000' : '#f9f9f9',
              borderBottom: `1px solid ${isDark ? '#1a1a1a' : '#eee'}`
            }}>
              <span style={modalId}>NODE_DATA // ID_{selectedItem.id}</span>
              <button onClick={() => setSelectedItem(null)} style={closeBtn}><X size={24}/></button>
            </div>
            
            <div style={{
              ...modalBody,
              background: isDark ? '#000000' : '#ffffff' // FORCED BLACK
            }}>
              <h3 style={{ ...modalTitle, color: isDark ? '#ffffff' : '#000000' }}>{selectedItem.goal}</h3>
              
              <div className="markdown-vault">
                <p style={labelSmall}><AlignLeft size={14}/> AGENTIC_RATIONALE</p>
                <div style={{
                  background: isDark ? '#080808' : '#f9f9f9',
                  padding: '1.5rem',
                  borderRadius: '12px',
                  border: `1px solid ${isDark ? '#111' : '#eee'}`
                }}>
                  <ReactMarkdown>{selectedItem.rationale}</ReactMarkdown>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .markdown-vault p { color: var(--text-primary) !important; font-size: 0.95rem; line-height: 1.6; }
        .vault-card { background: var(--bg-input); border: 1px solid var(--surface-border); border-radius: 16px; padding: 1.5rem; display: flex; align-items: center; }
        .reveal-node { animation: fadeIn 0.3s ease; }
        @keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
      `}</style>
    </div>
  );
};

/* ── UI Styles ── */
const containerStyle = { padding: '3rem 1.5rem', maxWidth: '900px', margin: '0 auto', background: 'var(--bg-primary)', minHeight: '100vh' };
const headerRow = { display: 'flex', justifyContent: 'space-between', marginBottom: '2rem', borderBottom: '1px solid var(--surface-border)', paddingBottom: '1rem' };
const headerStyle = { color: 'var(--text-primary)', fontSize: '1.4rem', fontWeight: 800, margin: 0 };
const vaultBadge = { fontSize: '0.75rem', color: 'var(--accent-primary)', fontWeight: 700, padding: '5px 12px', borderRadius: '8px', border: '1px solid' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1rem' };
const tagRow = { display: 'flex', gap: '1rem', marginBottom: '0.5rem' };
const metaText = { fontSize: '0.8rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '5px' };
const riskTag = { ...metaText, color: 'var(--accent-primary)', fontWeight: 800 };
const titleStyle = { margin: 0, color: 'var(--text-primary)', fontSize: '1.1rem' };
const actionColumn = { display: 'flex', gap: '15px', borderLeft: '1px solid var(--surface-border)', paddingLeft: '1.5rem', marginLeft: '1rem' };
const iconBtn = { background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };

const modalContent = { width: '92%', maxWidth: '800px', borderRadius: '20px', maxHeight: '85vh', display: 'flex', flexDirection: 'column', overflow: 'hidden' };
const modalHeader = { padding: '1.2rem 2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const modalId = { color: 'var(--accent-primary)', fontFamily: 'monospace', fontSize: '0.75rem', fontWeight: 800 };
const modalBody = { padding: '2.5rem', overflowY: 'auto' };
const modalTitle = { fontSize: '1.5rem', fontWeight: 800, marginBottom: '2rem' };
const labelSmall = { fontSize: '0.75rem', fontWeight: 900, color: 'var(--accent-primary)', marginBottom: '1rem', display: 'flex', alignItems: 'center', gap: '8px' };
const closeBtn = { background: 'none', border: 'none', color: 'var(--text-muted)', cursor: 'pointer' };
const centerStyle = { height: '80vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-primary)' };

export default VaultPage;
